+    fn test_batch_embedding() {
+        let indexer = SemanticIndexer::new("hash", None).unwrap();
+        let messages = vec![
+            EmbeddingInput::new(1, "Hello world"),
+            EmbeddingInput::new(2, "Goodbye world"),
